import java.lang.Math;

class Solution {
    /**
     * Reverses the digits of a number.
     * @param n The number to reverse.
     * @return The reversed number.
     */
    private long reverseNumber(long n) {
        long reversed = 0;
        long temp = n;
        while (temp > 0) {
            long digit = temp % 10;
            reversed = reversed * 10 + digit;
            temp /= 10;
        }
        return reversed;
    }

    /**
     * Checks if a number is prime.
     * @param num The number to check.
     * @return true if num is prime, false otherwise.
     */
    private boolean isPrime(long num) {
        if (num <= 1) {
            return false;
        }
        if (num <= 3) {
            return true;
        }
        if (num % 2 == 0 || num % 3 == 0) {
            return false;
        }
        for (long i = 5; i * i <= num; i = i + 6) {
            if (num % i == 0 || num % (i + 2) == 0) {
                return false;
            }
        }
        return true;
    }

    public long solve(long n) {
        long r = reverseNumber(n);

        long start = Math.min(n, r);
        long end = Math.max(n, r);

        long sumOfPrimes = 0;

        for (long i = start; i <= end; i++) {
            if (isPrime(i)) {
                sumOfPrimes += i;
            }
        }

        return sumOfPrimes;
    }
}
