    private long reverseNumber(long n) {
        long reversed = 0;
        long temp = n;
        while (temp > 0) {
            int digit = (int) (temp % 10);
            reversed = reversed * 10 + digit;
            temp /= 10;
        }
        return reversed;
    }

    /**
     * Returns the sum of all prime numbers between min(n, r) and max(n, r) inclusive,
     * where r is the reverse of n.
     * 
     * @param n The input integer.
     * @return The sum of prime numbers in the range.
     */
    public static long solve(long n) {
        Solution solution = new Solution();

        // 1. Reverse n to get r
        long r = solution.reverseNumber(n);

        // 2. Determine the range [start, end]
        long start = Math.min(n, r);
        long end = Math.max(n, r);

        long sumOfPrimes = 0;

        // 3. Iterate from start to end and sum up primes
        for (long i = start; i <= end; i++) {
            // Since n <= 1000, r <= 1000, so i will be small enough to cast to int for isPrime check safely (max 1000)
            if (solution.isPrime((int) i)) {
                sumOfPrimes += i;
            }
        }

        return sumOfPrimes;
